
import { ref, defineComponent, reactive, inject, toRefs } from "vue";
import {
  applyfor_monad,
  applyfor_details,
} from "@/server/http/api/Amultitasking";
const columns = [
  {
    title: "检测项名称",
    dataIndex: "checkItemName",
    key: "checkItemName",
  },
  {
    title: "检测项价格",
    dataIndex: "checkPrice",
    key: "checkPrice",
  },
  {
    title: "检测样次",
    dataIndex: "times",
    key: "times 1",
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    dataIndex: "standardName",
    key: "standardName",
  },
];
export default defineComponent({
  props: ["taskId"],
  setup(props) {
    let searchApplyfor: any = inject("searchApplyfor");

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    let options = reactive({
      details: {},
    });
    const showModal = () => {
      // applyfor_details(props.taskId).then((res: any) => {
      //   //console.log("审批详情", res);
      // });
      visible.value = true;
    };

    const handleOk = (id: number) => {
      confirmLoading.value = true;
      applyfor_monad(id).then((res: any) => {
        if (res.data.code === 200) {
          searchApplyfor();
        }
        visible.value = false;
        confirmLoading.value = false;
      });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      ...toRefs(options),
      columns,
    };
  },
});
