const columns1 = [
  {
    title: "报告编号",
    dataIndex: "reportCode",
    key: "reportCode",
  },
  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "本单费用",
    dataIndex: "cost",
    key: "cost",
  },
  {
    title: "要求完成日期",
    key: "requiredCompletionTime",
    dataIndex: "requiredCompletionTime",
  },

  {
    title: "审核人姓名",
    key: "verifyer",
    dataIndex: "verifyer",
  },

  {
    title: "报告提交申请人",
    key: "applicant",
    dataIndex: "applicant",
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

import { defineComponent, provide, reactive, ref, toRefs, watch } from "vue";
import GrabOrdersModel from "./model/Reportapproval/GrabOrdersModel.vue";
import ExamineModel from "./model/Reportapproval/ExamineModel.vue";
import GrabDetail from "./model/Reportapproval/GrabDetail.vue";
import ExamineDetail from "./model/Reportapproval/ExamineDetail.vue";
import {
  report_applyfor,
  applyfor_history,
} from "@/server/http/api/Amultitasking";
export default defineComponent({
  name: "Reportapproval",
  components: { GrabOrdersModel, ExamineModel, GrabDetail, ExamineDetail },
  setup() {
    let active = ref(0);
    let total = ref(0);

    let options = reactive({
      searchValue: "",
      state: 0,
      pageNum: 1,
      pageSize: 10,
    });
    let searchValue1 = ref("");
    let datatList = ref([]);
    let datatList1 = ref([]);

    let timer: any;
    // 监听历史数据
    watch(active, (newval) => {
      if (newval === 0) {
        searchApplyfor();
      } else {
        searchHistory();
      }
    });
    // 报告审批
    function searchApplyfor() {
      report_applyfor({
        search: options.searchValue,
        state: options.state,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("报告审批", res);
        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    watch(
      options,
      () => {
        clearTimeout(timer);
        timer = setTimeout(() => {
          searchApplyfor();
        }, 400);
      },
      {
        immediate: true,
      }
    );

    // 历史查询
    function searchHistory() {
      applyfor_history({
        search: searchValue1.value,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("报告审批历史", res);
        if (res.data.code === 200) {
          datatList1.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    watch(searchValue1, () => {
      clearTimeout(timer);

      timer = setTimeout(() => {
        searchHistory();
      }, 400);
    });
    // 报告审批
    provide("searchApplyfor", searchApplyfor);

    function onSearch() {}
    return {
      onSearch,
      datatList,
      columns,
      active,
      ...toRefs(options),
      columns1,
      total,
      datatList1,
      searchValue1,
    };
  },
});
