
import { ref, defineComponent, reactive, inject, toRefs } from "vue";
import {
  approval_data,
  applyfor_details,
  approval_download,
  download_init,
} from "@/server/http/api/Amultitasking";
import DownloadCheck from "../../model/Reportgeneration/DownloadCheck.vue";

const columns = [
  {
    title: "检测项名称",
    dataIndex: "checkItemName",
    key: "checkItemName",
  },
  {
    title: "检测项价格",
    dataIndex: "checkPrice",
    key: "checkPrice",
  },
  {
    title: "检测样次",
    dataIndex: "times",
    key: "times 1",
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    dataIndex: "standardName",
    key: "standardName",
  },
  {
    title: "操作",

    key: "action",
    slots: { customRender: "action" },
  },
];

export default defineComponent({
  props: ["taskId"],
  components: { DownloadCheck },
  setup(props) {
    let searchApplyfor: any = inject("searchApplyfor");
    const formState: any = reactive({
      state: 1,
      reason: "",
    });
    let options: any = reactive({
      details: {},
    });

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = () => {
      applyfor_details(props.taskId).then((res: any) => {
        //console.log("审批详情", res);
        if (res.data.code === 200) {
          options.details = res.data.data;
        }
      });
      visible.value = true;
    };

    const handleOk = (id: number) => {
      confirmLoading.value = true;
      approval_data({
        id: id,
        state: formState.state,
        reason: formState.reason,
      }).then((res: any) => {
        if (res.data.code === 200) {
          searchApplyfor();
        }
        visible.value = false;
        confirmLoading.value = false;
      });
    };
    function downLoad(record: any) {
      approval_download(
        options.details.entrustmentId,
        options.details.taskCode
      ).then((res: any) => {
        //console.log(res);
        
        const link = document.createElement("a");
        link.style.display = "none";
        link.setAttribute("href", res.data);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      });
    }
    function downloadinit(checkItemId: number) {
      download_init(checkItemId).then((res: any) => {
        //console.log(res);
        const link = document.createElement("a");
        link.style.display = "none";
        link.setAttribute("href", res.data);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      });
    }
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      formState,
      labelCol: { span: 12 },
      wrapperCol: { span: 8 },
      ...toRefs(options),
      columns,
      downLoad,
      downloadinit,
    };
  },
});
